import{_ as t,o as a,c as r,an as o}from"./chunks/framework.D5fFzH9V.js";const c=JSON.parse('{"title":"Email setup","description":"Configure email encryption (S/MIME) and legally required signatures/footers for eM Client, Nextcloud Mail, and Thunderbird.","frontmatter":{"title":"Email setup","description":"Configure email encryption (S/MIME) and legally required signatures/footers for eM Client, Nextcloud Mail, and Thunderbird."},"headers":[],"relativePath":"organization/human-resources/email-setup.md","filePath":"organization/human-resources/email-setup.md"}'),i={name:"organization/human-resources/email-setup.md"};function l(n,e,s,u,d,m){return a(),r("div",null,[...e[0]||(e[0]=[o('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /organization/human-resources/email-setup.md for this page in Markdown format</div><h1 id="email-setup" tabindex="-1">Email setup <a class="header-anchor" href="#email-setup" aria-label="Permalink to &quot;Email setup&quot;">​</a></h1><h2 id="email-encryption" tabindex="-1">Email encryption <a class="header-anchor" href="#email-encryption" aria-label="Permalink to &quot;Email encryption&quot;">​</a></h2><p>Emails are encrypted using S/MIME at the email gateway. Outgoing emails are signed and encrypted if the public key of the recipient is present. You cannot control signing and encryption from your email client.</p><p>Test (e.g. with your colleagues) if email encryption and signing works. It should work out of the box if we have acquired a certificate for your user account.</p><h2 id="email-footers" tabindex="-1">Email footers <a class="header-anchor" href="#email-footers" aria-label="Permalink to &quot;Email footers&quot;">​</a></h2><p>Email footers are <a href="https://www.wko.at/internetrecht/das-korrekte-e-mail-impressum" target="_blank" rel="noreferrer">legally required</a>.<br> The first email or the first reply to an email should include your email footer. This makes your contact details available to the recipients.<br> Follow-up emails don&#39;t have to include an email signature.</p><h3 id="em-client" tabindex="-1">eM Client <a class="header-anchor" href="#em-client" aria-label="Permalink to &quot;eM Client&quot;">​</a></h3><ol><li>Go to &quot;Settings&quot;</li><li>Go to &quot;Mail&quot; Menu</li><li>Go to &quot;Templates and Signatures&quot;</li><li>Import Sample Signatures <ul><li>Sample email footers: <a href="/assets/Syslifters.html" target="_blank" rel="noopener noreferrer">Syslifters.html</a></li><li>Sample email footers with SysReptor: <a href="/assets/SysReptor.html" target="_blank" rel="noopener noreferrer">SysReptor.html</a></li><li>Sample email footers with SysLeaks: <a href="/assets/SysLeaks.html" target="_blank" rel="noopener noreferrer">SysLeaks.html</a></li></ul></li><li>Update the email footer/signature with your data <ul><li>Your job title could be something like... <code>Security Penetration Tester</code>, <code>Pentester</code>, etc.</li></ul></li></ol><h3 id="em-client-mobile" tabindex="-1">eM Client (mobile) <a class="header-anchor" href="#em-client-mobile" aria-label="Permalink to &quot;eM Client (mobile)&quot;">​</a></h3><ol><li>QR Export your email footer in eM Client desktop</li><li>Go to &quot;Settings&quot; in eM Client on your phone</li><li>Click &quot;import/export&quot;</li><li>Scan the QR Code</li></ol><h3 id="nextcloud" tabindex="-1">NextCloud <a class="header-anchor" href="#nextcloud" aria-label="Permalink to &quot;NextCloud&quot;">​</a></h3><p>You can update your email footer in the <a href="https://cloud.syslifters.com/apps/mail/" target="_blank" rel="noreferrer">NextCloud mail app</a> via &quot;Account Settings&quot;/&quot;Signatures&quot;.<br> Copy and paste the signature below and update the data and the links.</p><blockquote><p><strong>ARON MOLNAR</strong><br><small>CO-FOUNDER</small><br><small>+43 660 923 40 60</small><br><small><a href="mailto:aron@syslifters.com" target="_blank" rel="noreferrer">aron@syslifters.com</a></small><br><small><a href="https://handbook.syslifters.com/about-us/aron" target="_blank" rel="noreferrer">More about me...</a><br><a href="https://www.syslifters.com" target="_blank" rel="noreferrer">www.syslifters.com</a></small></p><br><small>English · Deutsch · GernePerDu<br>Information gemäß § 14 Unternehmensgesetzbuch: Syslifters GmbH, Firmensitz: Eitzersthal 75, 2013 Göllersdorf, FN 578505v, Bezirksgericht Hollabrunn.</small></blockquote><h3 id="thunderbird" tabindex="-1">Thunderbird <a class="header-anchor" href="#thunderbird" aria-label="Permalink to &quot;Thunderbird&quot;">​</a></h3><p>Import the sample signatures from <a href="#em-client">eM Client</a>.</p><h2 id="setting-nextcloud-talk-as-online-meeting-provider" tabindex="-1">Setting Nextcloud Talk as online Meeting provider <a class="header-anchor" href="#setting-nextcloud-talk-as-online-meeting-provider" aria-label="Permalink to &quot;Setting Nextcloud Talk as online Meeting provider&quot;">​</a></h2><p>This works in eM Client only.</p><ol><li>Hamburger Menu on the top left: <code>Settings -&gt; Online Meetings -&gt; Add</code></li><li>Select &quot;Nextcloud Talk&quot; and when prompted for the URL enter: <code>https://cloud.syslifters.com</code>. Do <strong>not</strong> add a trailing slash, as the meeting URLs will not work!</li><li>Create a new app password in Nextcloud <code>Settings -&gt; Security</code> and paste your credentials into eM Client.</li></ol>',19)])])}const p=t(i,[["render",l]]);export{c as __pageData,p as default};
